{
  "grammar": [
    {
      "pattern": "想 + 要 + 退貨 / 換貨",
      "structure": ["想", "要", "退貨/換貨"],
      "explanation_en": "Use '想' to express a desire to return or exchange an item. This is a polite and direct way to state your intention in a store.",
      "title": "Expressing Desire to Return or Exchange",
      "meaning": "I want to return/exchange...",
      "when_to_use": ["When you want to return a defective item", "When you want to exchange for a different size or color"],
      "when_not_to_use": ["When you are just browsing", "When you want to complain without taking action"],
      "pragmatic_notes": "In Taiwan, it's common to start with '不好意思' or '請問' before this phrase to be polite. For example: '不好意思，我想要退貨。'",
      "word_order_notes": "The verb '想' comes before '要', and '退貨' or '換貨' is the object. No additional particles are needed.",
      "english_contrast": "In English, you might say 'I'd like to return this.' In Chinese, '想' softens the request, similar to 'would like'.",
      "korean_contrast": "In Korean, you might say '환불하고 싶습니다' (I want a refund). The structure '想 + 要' is similar to '~고 싶다'.",
      "negative_examples": [
        {
          "text": "我要退貨想。",
          "error": "The verb '想' must come before '要', not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想退貨要。",
          "error": "The verb '要' should come after '想', not at the end."
        }
      ],
      "transformation_drills": ["Change '退貨' to '換貨' to express exchange.", "Add '不好意思' at the beginning to make it more polite."],
      "production_drills": ["You bought a shirt that is too small. What do you say to the clerk?", "You received a broken cup. How do you tell the store you want to return it?"],
      "common_error_patterns": ["Placing '要' before '想'", "Omitting '要' and just saying '我想退貨' (acceptable but less common)"],
      "repair_feedback": {
        "word_order": "Remember: '想' comes before '要'.",
        "politeness": "Add '不好意思' at the beginning for politeness.",
        "vocabulary": "Use '退貨' for return and '換貨' for exchange."
      }
    },
    {
      "pattern": "有 + 問題 / 瑕疵",
      "structure": ["有", "問題/瑕疵"],
      "explanation_en": "Use '有' to indicate that an item has a problem or defect. This is a common way to explain why you want to return or exchange something.",
      "title": "Describing a Problem with an Item",
      "meaning": "There is a problem/defect...",
      "when_to_use": ["When the item is damaged or defective", "When the item doesn't work properly"],
      "when_not_to_use": ["When you simply changed your mind", "When the item is fine but you don't want it"],
      "pragmatic_notes": "In Taiwan, it's polite to explain the problem briefly. For example: '這個手機有問題，螢幕壞掉了。'",
      "word_order_notes": "The noun '問題' or '瑕疵' comes after '有'. You can add a specific description after it.",
      "english_contrast": "In English, you might say 'There's a problem with this.' In Chinese, '有' directly states existence.",
      "korean_contrast": "In Korean, you might say '문제가 있습니다' (There is a problem). The structure '有 + 問題' is similar.",
      "negative_examples": [
        {
          "text": "問題有這個手機。",
          "error": "The word order is incorrect. '有' should come before '問題'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "這個手機有問題瑕疵。",
          "error": "You should use either '問題' or '瑕疵', not both together."
        }
      ],
      "transformation_drills": ["Replace '問題' with '瑕疵' to specify a defect.", "Add a specific description like '螢幕壞掉了' after '問題'."],
      "production_drills": ["Your new phone has a cracked screen. How do you describe the problem?", "The shirt you bought has a stain. What do you say?"],
      "common_error_patterns": ["Using '是' instead of '有' (e.g., '是問題' is incorrect)", "Forgetting to specify the problem after '有問題'"],
      "repair_feedback": {
        "word_order": "Remember: '有' comes before the noun.",
        "politeness": "It's polite to explain the problem clearly.",
        "vocabulary": "Use '問題' for general problems and '瑕疵' for defects."
      }
    },
    {
      "pattern": "可以 + 換貨 / 退貨 + 嗎",
      "structure": ["可以", "換貨/退貨", "嗎"],
      "explanation_en": "Use '可以...嗎' to politely ask if it's possible to exchange or return an item. This is a common question in stores.",
      "title": "Asking for Permission to Exchange or Return",
      "meaning": "Can I exchange/return...?",
      "when_to_use": ["When you want to check the store's policy", "When you are unsure if an exchange is allowed"],
      "when_not_to_use": ["When you are sure about the policy", "When you are just stating your intention"],
      "pragmatic_notes": "In Taiwan, it's common to add '請問' at the beginning. For example: '請問，我可以換貨嗎？'",
      "word_order_notes": "The verb '可以' comes before the action (換貨/退貨), and '嗎' is at the end to form a question.",
      "english_contrast": "In English, you might say 'Can I exchange this?' The structure is similar, but Chinese uses '嗎' for yes/no questions.",
      "korean_contrast": "In Korean, you might say '교환할 수 있나요?' (Can I exchange?). The structure '可以...嗎' is similar to '~할 수 있나요?'.",
      "negative_examples": [
        {
          "text": "可以嗎換貨？",
          "error": "The action '換貨' should come before '嗎'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我可以換貨？",
          "error": "Without '嗎', this sounds like a statement, not a polite question."
        }
      ],
      "transformation_drills": ["Change '換貨' to '退貨' to ask about returns.", "Add '請問' at the beginning for extra politeness."],
      "production_drills": ["You want to exchange a shirt for a different size. What do you ask the clerk?", "You want to return a defective phone. How do you ask if it's possible?"],
      "common_error_patterns": ["Omitting '嗎' and using rising intonation only", "Placing '嗎' before the action"],
      "repair_feedback": {
        "word_order": "Remember: '可以' + action + '嗎'.",
        "politeness": "Add '請問' at the beginning for politeness.",
        "vocabulary": "Use '換貨' for exchange and '退貨' for return."
      }
    }
  ]
}
